#!/bin/bash
sed -i 's/fun AdminItemCard(/fun AdminItemCard(onPelangganClick: () -> Unit = {}, /g' app/src/main/java/com/example/ui/screens/UangDiAdminScreen.kt
sed -i 's/modifier = Modifier.clickable { selectedAdmin = admin; showDialog = true; coroutineScope.launch { try { isLoadingDialog = true; val allPayments = com.example.ui.data.remote.ApiClient.apiService.getPembayaranHistory(); dialogPayments = allPayments.filter { it.admin_name == admin.name } } catch(e: Exception) {} finally { isLoadingDialog = false } } }/modifier = Modifier.clickable { onPelangganClick() }/g' app/src/main/java/com/example/ui/screens/UangDiAdminScreen.kt
sed -i 's/AdminItemCard(/AdminItemCard(onPelangganClick = { selectedAdmin = admin; showDialog = true; coroutineScope.launch { try { isLoadingDialog = true; val allPayments = com.example.ui.data.remote.ApiClient.apiService.getPembayaranHistory(); dialogPayments = allPayments.filter { it.admin_name == admin.name } } catch(e: Exception) {} finally { isLoadingDialog = false } } }, /g' app/src/main/java/com/example/ui/screens/UangDiAdminScreen.kt
